// Do not edit this file as it will be overwritten if HAMR codegen is rerun

//! Place-assertion spec functions of property `normal_mode_alarm_off` -- one per
//! point its decoration binds (unbound points carry `true`, design D5).

#![allow(non_snake_case)]
#![allow(unused_imports)]

use data::*;
use vstd::prelude::*;

use crate::assertions::*;
use crate::system_state::SystemState;

verus! {

/** property normal_mode_alarm_off, bound 'after oi' (place after_oi)
  *   OI integration and alarm range constraints
  */
pub open spec fn sys_assert_normal_mode_alarm_off_after_oi(st: SystemState) -> bool
{
  (GUMBO_Library::Allowed_LowerAlarmTempWStatus_spec(st.lower_alarm_tempWstatus) && GUMBO_Library::Allowed_UpperAlarmTempWStatus_spec(st.upper_alarm_tempWstatus)) &&
    GUMBO_Library::Allowed_AlarmTempWStatus_Ranges_spec(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property normal_mode_alarm_off, bound 'at ts_oi_done' (place post_join_1)
  *   join: carried past ts
  */
pub open spec fn sys_assert_normal_mode_alarm_off_post_join_1(st: SystemState) -> bool
{
  (GUMBO_Library::Allowed_LowerAlarmTempWStatus_spec(st.lower_alarm_tempWstatus) && GUMBO_Library::Allowed_UpperAlarmTempWStatus_spec(st.upper_alarm_tempWstatus)) &&
    GUMBO_Library::Allowed_AlarmTempWStatus_Ranges_spec(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property normal_mode_alarm_off, bound 'before dmf' (place before_dmf)
  *   branch entry: alarm temp constraints carry in
  */
pub open spec fn sys_assert_normal_mode_alarm_off_before_dmf(st: SystemState) -> bool
{
  (GUMBO_Library::Allowed_LowerAlarmTempWStatus_spec(st.lower_alarm_tempWstatus) && GUMBO_Library::Allowed_UpperAlarmTempWStatus_spec(st.upper_alarm_tempWstatus)) &&
    GUMBO_Library::Allowed_AlarmTempWStatus_Ranges_spec(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property normal_mode_alarm_off, bound 'after dmf' (place after_dmf)
  *   frame condition preserves alarm temp constraints
  */
pub open spec fn sys_assert_normal_mode_alarm_off_after_dmf(st: SystemState) -> bool
{
  (GUMBO_Library::Allowed_LowerAlarmTempWStatus_spec(st.lower_alarm_tempWstatus) && GUMBO_Library::Allowed_UpperAlarmTempWStatus_spec(st.upper_alarm_tempWstatus)) &&
    GUMBO_Library::Allowed_AlarmTempWStatus_Ranges_spec(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property normal_mode_alarm_off, bound 'after mmi' (place after_mmi)
  *   derived from MMI component contract + write frame + pre-assertions;
  *   the alarm range properties hold only when the monitor interface is not failing
  *   (REQ-MMI-7 leaves the range UNSPECIFIED on failure)
  */
pub open spec fn sys_assert_normal_mode_alarm_off_after_mmi(st: SystemState) -> bool
{
  (sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && GUMBO_Library::Allowed_LowerAlarmTemp_spec(st.lower_alarm_temp.degrees)) &&
        GUMBO_Library::Allowed_UpperAlarmTemp_spec(st.upper_alarm_temp.degrees)))
}

/** property normal_mode_alarm_off, bound 'after mmm' (place after_mmm)
  *   frame condition preserves MMI properties;
  *   MMM additionally links NORMAL mode to the absence of interface failure
  */
pub open spec fn sys_assert_normal_mode_alarm_off_after_mmm(st: SystemState) -> bool
{
  ((sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && GUMBO_Library::Allowed_LowerAlarmTemp_spec(st.lower_alarm_temp.degrees)) &&
        GUMBO_Library::Allowed_UpperAlarmTemp_spec(st.upper_alarm_temp.degrees)))) &&
    ((st.monitor_mode == Isolette_Data_Model::Monitor_Mode::Normal_Monitor_Mode) ==>
      !(st.mon_interface_failure.flag))
}

/** property normal_mode_alarm_off, bound 'after ma' (place after_ma)
  *   end-to-end: normal mode alarm control (off within range)
  */
pub open spec fn sys_assert_normal_mode_alarm_off_after_ma(st: SystemState) -> bool
{
  ((((((st.lower_alarm_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid) &&
    (st.upper_alarm_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (st.current_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (st.monitor_mode == Isolette_Data_Model::Monitor_Mode::Normal_Monitor_Mode)) &&
    (st.current_tempWstatus.degrees >= st.lower_alarm_tempWstatus.degrees + 1i32)) &&
    (st.current_tempWstatus.degrees <= st.upper_alarm_tempWstatus.degrees - 1i32)) ==>
    (st.alarm_control == Isolette_Data_Model::On_Off::Off)
}

} // verus!
